arguments.new_str:
using Microsoft.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 0);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
IDataView dataView = mlContext.Data.LoadFromTextFile<ChurnData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" label to boolean, encode Region, and concatenate features
var pipeline = mlContext.Transforms.CustomMapping<ChurnData, LabelMapping>(
        (input, output) => output.Label = input.Churned.Equals("Yes", StringComparison.OrdinalIgnoreCase),
        contractName: "ChurnLabelMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnData.Age), nameof(ChurnData.Income),
        nameof(ChurnData.PurchaseHistory), "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(dataView);
var predictor = mlContext.Model.CreatePredictionEngine<ChurnData, ChurnPrediction>(model);

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (ChurnRequest req) =>
{
    var input = new ChurnData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = predictor.Predict(input);

    return Results.Ok(new
    {
        willChurn = prediction.PredictedLabel,
        probability = Math.Round(prediction.Probability, 4)
    });
});

app.Run();

public record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

public class LabelMapping
{
    public bool Label { get; set; }
}

